{"code":"const prs = github.list_pull_requests({ state: 'open' });
const count = prs.length;
const repoCounts = {};
prs.forEach(pr => {
  repoCounts[pr.repo] = (repoCounts[pr.repo] || 0) + 1;
});
const maxRepo = Object.keys(repoCounts).reduce((a, b) => repoCounts[a] > repoCounts[b] ? a : b);
{ count, maxRepo, maxCount: repoCounts[maxRepo] }"}

